    43→
    44→    /**
    45→     * Minheap of aborted transactions sorted by the transaction first offset
    46→     */
    47→    private final PriorityQueue<AbortedTxn> abortedTransactions = new PriorityQueue<>(
    48→            Comparator.comparingLong(AbortedTxn::firstOffset)
    49→    );
    50→
    51→    /**
